{"path":"rtl/arm_reg_file.sv","content":"//=============================================================================
// ARM Register File
// 32-bit x 16 registers (R0-R15) with dual read ports and single write port
// R13 = SP (Stack Pointer), R14 = LR (Link Register), R15 = PC (Program Counter)
//=============================================================================

module arm_reg_file (
    input  logic        clk,
    input  logic        rst_n,

    // Read port A
    input  logic [3:0]  raddr_a,
    output logic [31:0] rdata_a,

    // Read port B
    input  logic [3:0]  raddr_b,
    output logic [31:0] rdata_b,

    // Write port
    input  logic        we,          // Write enable
    input  logic [3:0]  waddr,
    input  logic [31:0] wdata,

    // PC direct access
    output logic [31:0] pc_out       // R15 = PC (current instruction address)
);

    logic [31:0] registers [0:15];

    // Synthesizable synchronous read
    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            for (int i = 0; i < 16; i++) begin
                registers[i] <= 32'd0;
            end
            registers[13] <= 32'h0000_1000;  // SP init
        end else begin
            // Write (R15 is handled separately for PC)
            if (we && waddr != 4'd15) begin
                registers[waddr] <= wdata;
            end
        end
    end

    // Asynchronous read — combinational
    assign rdata_a = (raddr_a == 4'd15) ? pc_out : registers[raddr_a];
    assign rdata_b = (raddr_b == 4'd15) ? pc_out : registers[raddr_b];

    // PC is R15 — exposed directly
    assign pc_out = registers[15];

endmodule
"}

{"content":"//=============================================================================
// ARM Barrel Shifter
// Supports: LSL, LSR, ASR, ROR, RRX
// Used for data-processing operand2 shifted immediates and register shifts
//=============================================================================

module arm_barrel_shifter (
    input  logic [31:0] operand,      // Input value to shift
    input  logic [11:0] shift_amount, // Shift amount (5-bit for register, immediate encoded)
    input  logic [1:0]  shift_type,   // 00=LSL, 01=LSR, 10=ASR, 11=ROR
    input  logic        shift_carry_in, // Carry flag input
    input  logic        is_imm,       // 1 = immediate shift (from instruction decode)

    output logic [31:0] result,       // Shifted result
    output logic        carry_out     // Carry output from shifter
);

    logic [4:0]  actual_shift;
    logic [31:0] shifted;
    logic        shifter_carry;

    // Determine actual shift amount
    // For immediate: shift_amount[11:7] is shift, [6:0] is rotate for imm8
    // For register: shift_amount[4:0]
    always_comb begin
        if (is_imm) begin
            // Rotated immediate: rotate_right by 2*rotate_imm
            actual_shift = {shift_amount[4:0], 1'b0}; // double the rotate field
        end else begin
            actual_shift = shift_amount[4:0];
        end
    end

    // Barrel shift operation
    always_comb begin
        shifted = 32'd0;
        shifter_carry = shift_carry_in;

        case (shift_type)
            2'b00: begin // LSL
                case (actual_shift)
                    5'd0:    begin shifted = operand;              shifter_carry = shift_carry_in; end
                    5'd1:    begin shifted = operand << 1;         shifter_carry = operand[31];    end
                    5'd2:    begin shifted = operand << 2;         shifter_carry = operand[30];    end
                    5'd3:    begin shifted = operand << 3;         shifter_carry = operand[29];    end
                    5'd4:    begin shifted = operand << 4;         shifter_carry = operand[28];    end
                    5'd5:    begin shifted = operand << 5;         shifter_carry = operand[27];    end
                    5'd6:    begin shifted = operand << 6;         shifter_carry = operand[26];    end
                    5'd7:    begin shifted = operand << 7;         shifter_carry = operand[25];    end
                    5'd8:    begin shifted = operand << 8;         shifter_carry = operand[24];    end
                    5'd16:   begin shifted = operand << 16;        shifter_carry = operand[16];    end
                    5'd24:   begin shifted = operand << 24;        shifter_carry = operand[8];     end
                    default: begin shifted = operand << actual_shift; shifter_carry = (actual_shift > 0) ? operand[32 - actual_shift] : shift_carry_in; end
                endcase
                if (actual_shift >= 5'd32) begin
                    shifted = 32'd0;
                    shifter_carry = (actual_shift == 5'd32) ? operand[0] : 1'b0;
                end
            end

            2'b01: begin // LSR
                if (actual_shift == 5'd0 && !is_imm) begin
                    // LSR #0 means LSR #32
                    shifted = 32'd0;
                    shifter_carry = operand[31];
                end else begin
                    case (actual_shift)
                        5'd1:    begin shifted = operand >> 1;         shifter_carry = operand[0];     end
                        5'd2:    begin shifted = operand >> 2;         shifter_carry = operand[1];     end
                        5'd8:    begin shifted = operand >> 8;         shifter_carry = operand[7];     end
                        5'd16:   begin shifted = operand >> 16;        shifter_carry = operand[15];    end
                        5'd24:   begin shifted = operand >> 24;        shifter_carry = operand[23];    end
                        default: begin shifted = operand >> actual_shift; shifter_carry = operand[actual_shift - 1]; end
                    endcase
                    if (actual_shift >= 5'd32) begin
                        shifted = 32'd0;
                        shifter_carry = (actual_shift == 5'd32) ? operand[31] : 1'b0;
                    end
                end
            end

            2'b10: begin // ASR
                if (actual_shift == 5'd0 && !is_imm) begin
                    // ASR #0 means ASR #32
                    shifted = {32{operand[31]}};
                    shifter_carry = operand[31];
                end else begin
                    case (actual_shift)
                        5'd1:  begin shifted = $signed(operand) >>> 1;  shifter_carry = operand[0]; end
                        5'd8:  begin shifted = $signed(operand) >>> 8;  shifter_carry = operand[7]; end
                        5'd16: begin shifted = $signed(operand) >>> 16; shifter_carry = operand[15]; end
                        default: begin shifted = $signed(operand) >>> actual_shift; shifter_carry = operand[actual_shift - 1]; end
                    endcase
                    if (actual_shift >= 5'd32) begin
                        shifted = {32{operand[31]}};
                        shifter_carry = operand[31];
                    end
                end
            end

            2'b11: begin // ROR
                if (actual_shift == 5'd0 && !is_imm) begin
                    // RRX (rotate right extended through carry)
                    shifted = {shift_carry_in, operand[31:1]};
                    shifter_carry = operand[0];
                end else begin
                    // ROR by actual_shift mod 32
                    logic [4:0] rot;
                    rot = actual_shift[4:0];
                    case (rot)
                        5'd0:  begin shifted = operand;           shifter_carry = operand[31]; end
                        5'd1:  begin shifted = {operand[0], operand[31:1]};   shifter_carry = operand[0];  end
                        5'd8:  begin shifted = {operand[7:0], operand[31:8]}; shifter_carry = operand[7];  end
                        5'd16: begin shifted = {operand[15:0], operand[31:16]}; shifter_carry = operand[15]; end
                        default: begin shifted = (operand >> rot) | (operand << (32 - rot)); shifter_carry = operand[rot - 1]; end
                    endcase
                end
            end
        endcase
    end

    assign result    = shifted;
    assign carry_out = shifter_carry;

endmodule
","path":"rtl/arm_barrel_shifter.sv"}

{"content":"//=============================================================================
// ARM ALU (Arithmetic Logic Unit)
// Supports ARM data-processing operations:
//   AND, EOR, SUB, RSB, ADD, ADC, SBC, RSC,
//   TST, TEQ, CMP, CMN, ORR, MOV, BIC, MVN
//=============================================================================

module arm_alu (
    input  logic [31:0] op_a,         // Operand A (Rn)
    input  logic [31:0] op_b,         // Operand B (shifter result)
    input  logic [3:0]  alu_op,       // ALU operation select
    input  logic        carry_in,     // CPSR carry flag
    input  logic        update_flags, // S-bit: update CPSR flags

    output logic [31:0] result,       // ALU result
    output logic        flag_n,       // Negative flag
    output logic        flag_z,       // Zero flag
    output logic        flag_c,       // Carry flag
    output logic        flag_v        // Overflow flag
);

    logic [31:0] alu_result;
    logic        alu_carry;
    logic        alu_overflow;
    logic [32:0] add_result;  // 33-bit for carry
    logic [32:0] sub_result;

    // 64-bit for multiply (optional extension)
    logic [63:0] mul_result;

    always_comb begin
        alu_result  = 32'd0;
        alu_carry   = carry_in;
        alu_overflow = 1'b0;

        case (alu_op)
            // AND: Rd = Rn AND Op2
            4'h0: begin
                alu_result = op_a & op_b;
                alu_carry  = carry_in; // carry from shifter
            end

            // EOR: Rd = Rn XOR Op2
            4'h1: begin
                alu_result = op_a ^ op_b;
                alu_carry  = carry_in;
            end

            // SUB: Rd = Rn - Op2
            4'h2: begin
                sub_result = {1'b0, op_a} - {1'b0, op_b};
                alu_result = sub_result[31:0];
                alu_carry  = ~sub_result[32]; // inverted for SUB
                alu_overflow = (op_a[31] != op_b[31]) && (alu_result[31] != op_a[31]);
            end

            // RSB: Rd = Op2 - Rn
            4'h3: begin
                sub_result = {1'b0, op_b} - {1'b0, op_a};
                alu_result = sub_result[31:0];
                alu_carry  = ~sub_result[32];
                alu_overflow = (op_a[31] != op_b[31]) && (alu_result[31] != op_b[31]);
            end

            // ADD: Rd = Rn + Op2
            4'h4: begin
                add_result = {1'b0, op_a} + {1'b0, op_b};
                alu_result = add_result[31:0];
                alu_carry  = add_result[32];
                alu_overflow = (op_a[31] == op_b[31]) && (alu_result[31] != op_a[31]);
            end

            // ADC: Rd = Rn + Op2 + Carry
            4'h5: begin
                add_result = {1'b0, op_a} + {1'b0, op_b} + {32'd0, carry_in};
                alu_result = add_result[31:0];
                alu_carry  = add_result[32];
                alu_overflow = (op_a[31] == op_b[31]) && (alu_result[31] != op_a[31]);
            end

            // SBC: Rd = Rn - Op2 - !Carry
            4'h6: begin
                sub_result = {1'b0, op_a} - {1'b0, op_b} - {32'd0, ~carry_in};
                alu_result = sub_result[31:0];
                alu_carry  = ~sub_result[32];
                alu_overflow = (op_a[31] != op_b[31]) && (alu_result[31] != op_a[31]);
            end

            // RSC: Rd = Op2 - Rn - !Carry
            4'h7: begin
                sub_result = {1'b0, op_b} - {1'b0, op_a} - {32'd0, ~carry_in};
                alu_result = sub_result[31:0];
                alu_carry  = ~sub_result[32];
                alu_overflow = (op_a[31] != op_b[31]) && (alu_result[31] != op_b[31]);
            end

            // TST: Rn AND Op2 (result not written, flags updated)
            4'h8: begin
                alu_result = op_a & op_b;
                alu_carry  = carry_in;
            end

            // TEQ: Rn XOR Op2
            4'h9: begin
                alu_result = op_a ^ op_b;
                alu_carry  = carry_in;
            end

            // CMP: Rn - Op2 (flags only)
            4'hA: begin
                sub_result = {1'b0, op_a} - {1'b0, op_b};
                alu_result = sub_result[31:0];
                alu_carry  = ~sub_result[32];
                alu_overflow = (op_a[31] != op_b[31]) && (alu_result[31] != op_a[31]);
            end

            // CMN: Rn + Op2 (flags only)
            4'hB: begin
                add_result = {1'b0, op_a} + {1'b0, op_b};
                alu_result = add_result[31:0];
                alu_carry  = add_result[32];
                alu_overflow = (op_a[31] == op_b[31]) && (alu_result[31] != op_a[31]);
            end

            // ORR: Rd = Rn OR Op2
            4'hC: begin
                alu_result = op_a | op_b;
                alu_carry  = carry_in;
            end

            // MOV: Rd = Op2
            4'hD: begin
                alu_result = op_b;
                alu_carry  = carry_in;
            end

            // BIC: Rd = Rn AND NOT Op2
            4'hE: begin
                alu_result = op_a & ~op_b;
                alu_carry  = carry_in;
            end

            // MVN: Rd = NOT Op2
            4'hF: begin
                alu_result = ~op_b;
                alu_carry  = carry_in;
            end

            default: begin
                alu_result  = 32'd0;
                alu_carry   = carry_in;
                alu_overflow = 1'b0;
            end
        endcase
    end

    // Flag generation
    always_comb begin
        if (update_flags) begin
            flag_n = alu_result[31];
            flag_z = (alu_result == 32'd0);
            flag_c = alu_carry;
            flag_v = alu_overflow;
        end else begin
            flag_n = 1'b0;
            flag_z = 1'b0;
            flag_c = carry_in;
            flag_v = 1'b0;
        end
    end

    assign result = alu_result;

endmodule
